const INSTANCE_ID = $('Set Instance Context').first().json.INSTANCE_ID;

const inItem = $input.first().json;
const raw = inItem.data ?? '';

if (typeof raw !== 'string' || raw.length === 0) {
  return [{ json: { error: 'No metrics text found in $json.data', gotType: typeof raw } }];
}
const text = raw.includes('\\n') ? raw.replace(/\\n/g, '\n') : raw;
const samples = [];
const helpByName = new Map();
const typeByName = new Map();

function parseLabels(labelsStr) {
  if (!labelsStr) return {};
  const parts = labelsStr.split(/,(?=(?:[^"]*"[^"]*")*[^"]*$)/);
  const labels = {};
  for (const part of parts) {
    const p = part.trim();
    if (!p) continue;
    const eq = p.indexOf('=');
    if (eq === -1) continue;
    const key = p.slice(0, eq).trim();
    let val = p.slice(eq + 1).trim();
    val = val.replace(/^"|"$/g, '');   // remove surrounding quotes
    val = val.replace(/\\"/g, '"');    // unescape quotes
    val = val.replace(/\\\\/g, '\\');  // unescape backslash
    labels[key] = val;
  }
  return labels;
}

const lines = text.split('\n');

for (const line of lines) {
  const l = line.trim();
  if (!l) continue;

  if (l.startsWith('# HELP ')) {
    const m = l.match(/^# HELP ([^\s]+)\s+(.+)$/);
    if (m) helpByName.set(m[1], m[2]);
    continue;
  }

  if (l.startsWith('# TYPE ')) {
    const m = l.match(/^# TYPE ([^\s]+)\s+([^\s]+)$/);
    if (m) typeByName.set(m[1], m[2]);
    continue;
  }

  if (l.startsWith('#')) continue;
  const m = l.match(
    /^([a-zA-Z_:][a-zA-Z0-9_:]*)(\{([^}]*)\})?\s+([+-]?\d+(\.\d+)?([eE][+-]?\d+)?)(\s+(\d+))?$/
  );
  if (!m) continue;

  const name = m[1];
  const labelsStr = m[3] || '';
  const value = Number(m[4]);
  const ts = m[8] ? Number(m[8]) : null;

  samples.push({
    name,
    labels: parseLabels(labelsStr),
    value: Number.isFinite(value) ? value : null,
    type: typeByName.get(name) ?? null,
    help: helpByName.get(name) ?? null,
    sample_timestamp: ts,
  });
}

function pickValue(metricName) {
  const s = samples.find(x => x.name === metricName && Object.keys(x.labels).length === 0);
  return s?.value ?? null;
}

function pickLabels(metricName) {
  const s = samples.find(x => x.name === metricName);
  return s?.labels ?? null;
}

const n8nVersionLabels = pickLabels('n8n_version_info');
const nodeVersionLabels = pickLabels('n8n_nodejs_version_info');

const out = {
  INSTANCE_ID,
  timestamp: new Date().toISOString(),
  INSTANCE_ID,

  n8n_version: n8nVersionLabels?.version ?? null,
  node_version: nodeVersionLabels?.version ?? null,

  process_start_time_seconds: pickValue('n8n_process_start_time_seconds'),

  cpu_total_seconds: pickValue('n8n_process_cpu_seconds_total'),
  cpu_user_seconds: pickValue('n8n_process_cpu_user_seconds_total'),
  cpu_system_seconds: pickValue('n8n_process_cpu_system_seconds_total'),

  memory_rss_bytes: pickValue('n8n_process_resident_memory_bytes'),
  heap_used_bytes: pickValue('n8n_nodejs_heap_size_used_bytes'),
  external_memory_bytes: pickValue('n8n_nodejs_external_memory_bytes'),

  eventloop_lag_p99_s: pickValue('n8n_nodejs_eventloop_lag_p99_seconds'),
  open_fds: pickValue('n8n_process_open_fds'),

  active_workflows: pickValue('n8n_active_workflow_count'),
  is_leader: pickValue('n8n_instance_role_leader') === 1,

  samplesCount: samples.length,
  samples,
};

return [{ json: out }];
